Test asserts middleware rejects X-Gateway-User-Id when signature missing or wrong. Three cases cover the bypass: no signature, bad signature, legacy header. All must fail closed (raise Unauthorized or return None that caller treats as deny). Golden path — valid HMAC — must still return the user, otherwise test proves nothing.

```python
import pytest
from app.middleware.auth import AuthMiddleware, Unauthorized

SECRET = b"gateway-hmac-key"

@pytest.fixture
def mw():
    return AuthMiddleware(secret=SECRET, sessions={})

def sign(uid: str) -> str:
    import hmac, hashlib
    return hmac.new(SECRET, uid.encode(), hashlib.sha256).hexdigest()

def req(headers=None, cookies=None):
    from types import SimpleNamespace
    return SimpleNamespace(headers=headers or {}, cookies=cookies or {})

def test_valid_signature_resolves_user(mw):
    uid = "alice"
    r = req({"X-Gateway-User-Id": uid, "X-Gateway-Signature": sign(uid)})
    assert mw.resolve_user(r).id == "alice"

def test_missing_signature_rejected(mw):
    r = req({"X-Gateway-User-Id": "alice"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(r)

def test_bad_signature_rejected(mw):
    r = req({"X-Gateway-User-Id": "alice", "X-Gateway-Signature": "deadbeef"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(r)

def test_signature_for_different_uid_rejected(mw):
    r = req({"X-Gateway-User-Id": "admin", "X-Gateway-Signature": sign("alice")})
    with pytest.raises(Unauthorized):
        mw.resolve_user(r)

def test_legacy_x_user_id_header_rejected(mw):
    r = req({"X-User-Id": "admin"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(r)

def test_no_credentials_rejected(mw):
    with pytest.raises(Unauthorized):
        mw.resolve_user(req())
```

Key move: `test_signature_for_different_uid_rejected` catches signature-reuse attacks where attacker replays a valid signature against a different uid. `test_legacy_x_user_id_header_rejected` locks the door on the unsigned fallback so nobody re-adds it.
